// math.h runtime helpers should link and return plausible values.
// expected: exit=0
#include <assert.h>
#include <fenv.h>
#include <math.h>

static int near1000(double v, int lo, int hi) {
  int n = (int)(v * 1000.0);
  return n >= lo && n <= hi;
}

static int near1000f(float v, int lo, int hi) {
  int n = (int)(v * 1000.0f);
  return n >= lo && n <= hi;
}

static int nanish(long double v) {
  return v != 0.0L && !(v < 0.0L) && !(v > 0.0L);
}

int main(void) {
  double z = 0.0;
  double nanv = z / z;
  double asin_domain = asin(2.0);
  double asin_nan = asin(nanv);
  double acos_domain = acos(2.0);
  double acos_nan = acos(nanv);
  float asinf_domain = asinf(2.0f);
  long double acosl_domain = acosl(2.0L);
  double sqrt_neg = sqrt(-1.0);
  double sqrt_nan = sqrt(nanv);
  double sqrt_nzero = sqrt(-z);
  double sqrt_inf = sqrt(1.0 / z);
  float sqrtf_neg = sqrtf(-1.0f);
  long double sqrtl_neg = sqrtl(-1.0L);
  double pow_neg_frac = pow(-2.0, 0.5);
  double pow_nan = pow(nanv, 2.0);
  float powf_neg_frac = powf(-2.0f, 0.5f);
  long double powl_neg_frac = powl(-2.0L, 0.5L);
  double log_neg = log(-1.0);
  double log_nan = log(nanv);
  float logf_neg = logf(-1.0f);
  long double logl_neg = logl(-1.0L);
  double exp_nan = exp(nanv);
  float expf_nan = expf((float)nanv);
  long double expl_nan = expl((long double)nanv);
  double sin_inf = sin(1.0 / z);
  double cos_inf = cos(1.0 / z);
  double tan_inf = tan(1.0 / z);
  float sinf_inf = sinf(1.0f / 0.0f);
  long double cosl_inf = cosl(1.0L / z);
  long double tanl_inf = tanl(1.0L / z);
  double modf_int = 1.0;
  float modff_int = 1.0f;
  long double modfl_int = 1.0L;
  int remquo_bits = 0;
  int remquo_large_bits = 0;
  int remquo_large_neg_bits = 0;
  double acosh_domain = acosh(0.5);
  double atanh_domain = atanh(2.0);
  float acoshf_domain = acoshf(0.5f);
  long double atanhl_domain = atanhl(2.0L);

  assert(near1000(sin(1.5707963267948966), 998, 1002));
  assert(nanish(sin_inf));
  assert(nanish(sinf_inf));
  assert(near1000(cos(3.141592653589793), -1002, -998));
  assert(nanish(cos_inf));
  assert(nanish(cosl_inf));
  assert(near1000(tan(0.7853981633974483), 998, 1002));
  assert(nanish(tan_inf));
  assert(nanish(tanl_inf));
  assert(near1000(exp(1.0), 2716, 2720));
  assert(exp(1.0 / z) > 1.0e300);
  assert(exp(-1.0 / z) == 0.0);
  assert(nanish(exp_nan));
  assert(nanish(expf_nan));
  assert(nanish(expl_nan));
  assert(1.0 / expm1(-z) < 0.0);
  assert(1.0f / expm1f(-0.0f) < 0.0f);
  assert(1.0L / expm1l(-0.0L) < 0.0L);
  assert(near1000(log(2.718281828459045), 998, 1002));
  assert(log(z) < -1.0e300);
  assert(log(1.0 / z) > 1.0e300);
  assert(nanish(log_neg));
  assert(nanish(log_nan));
  assert(nanish(logf_neg));
  assert(nanish(logl_neg));
  assert(1.0 / log1p(-z) < 0.0);
  assert(1.0f / log1pf(-0.0f) < 0.0f);
  assert(1.0L / log1pl(-0.0L) < 0.0L);
  assert(near1000(log2(8.0), 2998, 3002));
  assert(log2(z) < -1.0e300);
  assert(nanish(log2(-1.0)));
  assert(near1000(log10(100.0), 1998, 2002));
  assert(log10(1.0 / z) > 1.0e300);
  assert(nanish(log10(-1.0)));
  assert(near1000(erf(1.0), 841, 844));
  assert(near1000f(erff(1.0f), 841, 844));
  assert(near1000(erfl(1.0L), 841, 844));
  assert(near1000(erfc(1.0), 156, 158));
  assert(near1000f(erfcf(1.0f), 156, 158));
  assert(near1000(erfcl(1.0L), 156, 158));
  assert(near1000(atan(1.0), 783, 787));
  assert(near1000(atan2(1.0, 0.0), 1568, 1572));
  assert(1.0 / atan2(-z, z) < 0.0);
  assert(near1000(atan2(z, -z), 3140, 3143));
  assert(near1000(atan2(-z, -z), -3143, -3140));
  assert(near1000(atan2(1.0 / z, 1.0 / z), 783, 787));
  assert(near1000(atan2(1.0 / z, -1.0 / z), 2354, 2358));
  assert(near1000(atan2(-1.0 / z, -1.0 / z), -2358, -2354));
  assert(near1000(asin(1.0), 1568, 1572));
  assert(nanish(asin_domain));
  assert(nanish(asin_nan));
  assert(nanish(asinf_domain));
  assert(near1000(acos(0.0), 1568, 1572));
  assert(nanish(acos_domain));
  assert(nanish(acos_nan));
  assert(nanish(acosl_domain));
  assert(near1000(sinh(0.0), 0, 0));
  assert(sinh(1.0 / z) > 1.0e300);
  assert(sinh(-1.0 / z) < -1.0e300);
  assert(near1000(cosh(0.0), 998, 1002));
  assert(cosh(1.0 / z) > 1.0e300);
  assert(cosh(-1.0 / z) > 1.0e300);
  assert(near1000(tanh(1.0), 759, 763));
  assert((int)tanh(1.0 / z) == 1);
  assert((int)tanh(-1.0 / z) == -1);
  assert(near1000(asinh(1.0), 880, 882));
  assert(near1000f(asinhf(1.0f), 880, 882));
  assert(near1000(asinhl(1.0L), 880, 882));
  assert(asinh(1.0 / z) > 1.0e300);
  assert(asinh(1.0e200) > 400.0 && asinh(1.0e200) < 500.0);
  assert(asinh(-1.0e200) < -400.0 && asinh(-1.0e200) > -500.0);
  assert(near1000(acosh(2.0), 1315, 1317));
  assert(near1000f(acoshf(2.0f), 1315, 1317));
  assert(near1000(acoshl(2.0L), 1315, 1317));
  assert(nanish(acosh_domain));
  assert(nanish(acoshf_domain));
  assert(acosh(1.0 / z) > 1.0e300);
  assert(acosh(1.0e200) > 400.0 && acosh(1.0e200) < 500.0);
  assert(acoshl(1.0e200L) > 400.0L && acoshl(1.0e200L) < 500.0L);
  assert(near1000(atanh(0.5), 548, 550));
  assert(near1000f(atanhf(0.5f), 548, 550));
  assert(near1000(atanhl(0.5L), 548, 550));
  assert(atanh(1.0) > 1.0e300);
  assert(atanh(-1.0) < -1.0e300);
  assert(nanish(atanh_domain));
  assert(nanish(atanhl_domain));
  assert(near1000(fmod(7.5, 2.0), 1498, 1502));
  assert(near1000f(fmodf(7.5f, 2.0f), 1498, 1502));
  assert(near1000(fmodl(7.5L, 2.0L), 1498, 1502));
  assert(nanish(fmod(7.5, 0.0)));
  assert(nanish(fmod(1.0 / z, 2.0)));
  assert((int)fmod(7.5, 1.0 / z) == 7);
  assert(1.0 / fmod(-z, 3.0) < 0.0);
  assert(nanish(fmodf(7.5f, 0.0f)));
  assert(nanish(fmodl(7.5L, 0.0L)));
  assert(fmod(1.0e20, 3.0) >= 0.0 && fabs(fmod(1.0e20, 3.0)) < 3.0);
  assert(fmod(-1.0e20, 3.0) <= 0.0 && fabs(fmod(-1.0e20, 3.0)) < 3.0);
  assert(fabs(fmodl(1.0e20L, 3.0L)) < 3.0L);
  assert(near1000(remainder(5.5, 2.0), -502, -498));
  assert(near1000(remquo(5.5, 2.0, &remquo_bits), -502, -498));
  assert(remquo_bits == 3);
  assert(fabs(remainder(1.0e20, 3.0)) <= 1.5);
  assert(fabs(remquo(1.0e20, 3.0, &remquo_large_bits)) <= 1.5);
  assert(fabs(remquo(-1.0e20, 3.0, &remquo_large_neg_bits)) <= 1.5);
  assert(1.0 / modf(-z, &modf_int) < 0.0 && 1.0 / modf_int < 0.0);
  assert(1.0f / modff(-2.0f, &modff_int) < 0.0f && (int)modff_int == -2);
  assert(1.0L / modfl(-0.0L, &modfl_int) < 0.0L && 1.0L / modfl_int < 0.0L);
  assert(near1000(hypot(3.0, 4.0), 4998, 5002));
  assert(near1000f(hypotf(3.0f, 4.0f), 4998, 5002));
  assert(near1000(hypotl(3.0L, 4.0L), 4998, 5002));
  assert(hypot(1.0e200, 1.0e200) > 1.0e200);
  assert(hypot(1.0 / z, nanv) > 1.0e300);
  assert(nanish(hypot(nanv, 3.0)));
  assert(near1000(scalbn(0.75, 4), 11998, 12002));
  assert(near1000f(scalbnf(0.5f, 5), 15998, 16002));
  assert(near1000(scalbnl(0.25L, 6), 15998, 16002));
  assert(near1000(scalbln(1.5, 3L), 11998, 12002));
  assert(near1000f(scalblnf(1.25f, 2L), 4998, 5002));
  assert(near1000(scalblnl(3.0L, -1L), 1498, 1502));
  assert(ldexp(1.0, 5000) > 1.0e300);
  assert(1.0 / ldexp(-1.0, -5000) < 0.0);
  assert(scalbln(1.0, 5000L) > 1.0e300);
  assert(1.0 / scalbln(-1.0, -5000L) < 0.0);
  assert(scalblnf(1.0f, 5000L) > 1.0e30f);
  assert(1.0L / scalblnl(-1.0L, -5000L) < 0.0L);
  assert(ilogb(8.0) == 3);
  assert(ilogbf(0.75f) == -1);
  assert(ilogbl(0.25L) == -2);
  assert((int)logb(8.0) == 3);
  assert((int)logbf(0.75f) == -1);
  assert((int)logbl(0.25L) == -2);
  assert((int)fmin(nanv, 7.0) == 7);
  assert((int)fmin(7.0, nanv) == 7);
  assert((int)fminf((float)nanv, 5.0f) == 5);
  assert((int)fminl(6.0L, (long double)nanv) == 6);
  assert(1.0 / fmin(-z, z) < 0.0);
  assert(1.0 / fmin(z, -z) < 0.0);
  assert((int)fmax(nanv, 7.0) == 7);
  assert((int)fmax(7.0, nanv) == 7);
  assert((int)fmaxf((float)nanv, 5.0f) == 5);
  assert((int)fmaxl(6.0L, (long double)nanv) == 6);
  assert(1.0 / fmax(-z, z) > 0.0);
  assert(1.0 / fmax(z, -z) > 0.0);
  assert(near1000(cbrt(27.0), 2998, 3002));
  assert(cbrt(1.0 / z) > 1.0e300);
  assert(cbrt(-1.0 / z) < -1.0e300);
  assert(nanish(cbrt(nanv)));
  assert(1.0 / cbrt(-z) < 0.0);
  assert(nanish(cbrtf((float)nanv)));
  assert(cbrtl(1.0L / z) > 1.0e300L);
  assert(near1000(pow(-2.0, 3.0), -8000, -8000));
  assert(near1000(pow(9.0, 0.5), 2998, 3002));
  assert(near1000f(powf(2.0f, 5.0f), 31998, 32002));
  assert(near1000(powl(2.0L, 4.0L), 15998, 16002));
  assert(nanish(pow_neg_frac));
  assert(nanish(pow_nan));
  assert(nanish(powf_neg_frac));
  assert(nanish(powl_neg_frac));
  assert((int)pow(nanv, 0.0) == 1);
  assert(pow(z, -0.5) > 1.0e300);
  assert(1.0 / pow(-z, 3.0) < 0.0);
  assert(pow(-z, -3.0) < -1.0e300);
  assert((int)floor(-3.2) == -4);
  assert((int)ceil(-3.8) == -3);
  assert((int)round(-3.5) == -4);
  assert((int)trunc(-3.8) == -3);
  assert(nanish(floor(nanv)));
  assert(ceil(1.0 / z) > 1.0e300);
  assert(round(-1.0 / z) < -1.0e300);
  assert(1.0 / floor(-z) < 0.0);
  assert(1.0 / trunc(-0.8) < 0.0);
  assert(1.0 / ceil(-0.8) < 0.0);
  assert(1.0 / round(-0.3) < 0.0);
  assert(nanish(floorf((float)nanv)));
  assert(ceill(1.0L / z) > 1.0e300L);
  assert(1.0L / roundl(-0.3L) < 0.0L);
  assert(near1000(fabs(-2.5), 2498, 2502));
  assert(near1000f(fabsf(-2.5f), 2498, 2502));
  assert(near1000(fabsl(-4.5L), 4498, 4502));
  assert(1.0 / fabs(-z) > 0.0);
  assert(1.0f / fabsf(-0.0f) > 0.0f);
  assert(1.0L / fabsl(-0.0L) > 0.0L);
  assert(1.0 / copysign(-z, 1.0) > 0.0);
  assert(1.0f / copysignf(-0.0f, 1.0f) > 0.0f);
  assert(1.0L / copysignl(-0.0L, 1.0L) > 0.0L);
  assert(near1000(sqrtl(2.0L), 1412, 1416));
  assert(nanish(sqrt_neg));
  assert(nanish(sqrt_nan));
  assert(1.0 / sqrt_nzero < 0.0);
  assert(sqrt_inf > 1.0e300);
  assert(nanish(sqrtf_neg));
  assert(nanish(sqrtl_neg));
  assert((int)floorf(2.9f) == 2);
  assert((int)ceilf(2.1f) == 3);
  assert((int)roundf(-2.5f) == -3);
  assert(nearbyint(2.5) == 2.0);
  assert(nearbyint(3.5) == 4.0);
  assert(nearbyintf(-2.5f) == -2.0f);
  assert(nearbyintl(-3.5L) == -4.0L);
  assert(lround(2.5) == 3);
  assert(lroundf(-2.5f) == -3);
  assert(lroundl(3.5L) == 4);
  assert(llround(-3.5) == -4);
  assert(llroundf(2.5f) == 3);
  assert(llroundl(-2.5L) == -3);
  assert(fesetround(FE_UPWARD) == 0);
  assert(rint(2.1) == 3.0);
  assert(rintf(-2.1f) == -2.0f);
  assert(lrint(2.1) == 3);
  assert(llrintf(-2.1f) == -2);
  assert(fesetround(FE_DOWNWARD) == 0);
  assert(rintl(2.9L) == 2.0L);
  assert(nearbyint(-2.1) == -3.0);
  assert(lrintl(2.9L) == 2);
  assert(llrintl(-2.1L) == -3);
  assert(fesetround(FE_TOWARDZERO) == 0);
  assert(rint(2.9) == 2.0);
  assert(rint(-2.9) == -2.0);
  assert(lrintf(2.9f) == 2);
  assert(llrint(-2.9) == -2);
  assert(fesetround(FE_TONEAREST) == 0);
  assert(rint(2.5) == 2.0);
  assert(rint(3.5) == 4.0);
  return 0;
}
